int fact[maxN+1]; // Deve ser inicializado com -1 (ou utilizar map)

int factorial(int n) {
    if(n &lt;= 1) return 1;
    if(fact[n] == -1) {
        fact[n] = n * factorial(n-1);
    }

    return fact[n];
}
